  --text-lg: 1.08rem;
  --text-xl: 1.28rem;
  --text-2xl: clamp(1.75rem, 3.8vw, 2.55rem);
  --text-display: clamp(1.95rem, 5vw, 3.35rem);
  --measure: 65ch;
  --container-max: 84rem;
  --font-display: "Avenir Next", "Segoe UI Variable", "Helvetica Neue", sans-serif;
  --font-body: "Avenir Next", "Segoe UI Variable", "Helvetica Neue", sans-serif;
  --font-ui: "Avenir Next", "Segoe UI Variable", "Helvetica Neue", sans-serif;
  --font-mono: "IBM Plex Mono", "SFMono-Regular", Menlo, Consolas, monospace;
}

* {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  min-height: 100%;
}

body {
  background:
    radial-gradient(circle at top left, rgba(148, 163, 184, 0.18), transparent 31rem),
    radial-gradient(circle at top right, rgba(191, 219, 254, 0.14), transparent 27rem),
    linear-gradient(180deg, #f8fafc 0%, #edf2f7 48%, #e5ebf2 100%);
  color: var(--ink);
  font-family: var(--font-body);
  font-size: var(--text-body);
  letter-spacing: -0.01em;
  text-rendering: optimizeLegibility;
}

a {
  color: inherit;
  text-decoration: none;
}

button,
input,
textarea {
  font: inherit;
}

::selection {
  background: rgba(50, 72, 99, 0.18);
}

.page-shell {
  min-height: 100vh;
  padding: var(--space-4);
}

.site-main {
  width: 100%;
}

.site-header,
.feature-layout,
.vault-shell,
.note-editor-shell {
  margin: 0 auto;
  max-width: var(--container-max);
}

.site-header {
  align-items: flex-start;
  backdrop-filter: blur(20px);
  background: rgba(255, 255, 255, 0.72);
  border: 1px solid rgba(148, 163, 184, 0.28);
  border-radius: var(--radius-4);
  box-shadow: var(--shadow-soft);
  display: flex;
  flex-direction: column;
  gap: var(--space-4);
  margin-bottom: var(--space-6);
  padding: 0.95rem 1.05rem;
}

.brand-block,
.hero-copy,
.vault-frame-copy {
  display: grid;
  gap: var(--space-2);
}

.brand {
  font-family: var(--font-ui);
  font-size: 0.92rem;
  font-weight: 700;
  letter-spacing: 0.2em;
  text-transform: uppercase;
}

.brand-caption,
.lede,
.field-note,
.auth-note,
.signin-error,
.status-note,
.note-list-item p,
.panel-card p,
.feature-card p,
.link-url,
.link-summary,
.note-generated-summary,
.note-generated-copy p,
.section-meta,
.tag-filter-count,
.vault-frame-note {
  color: var(--ink-muted);
}

.brand-caption,
.vault-frame-note,
.lede,
.field-note,
.auth-note,
.signin-error,
.status-note,
.link-url,
.link-summary,
.note-generated-summary,
.note-generated-copy p,
.note-list-item p {
  line-height: 1.65;
  margin: 0;
}

.brand-caption {
  font-size: var(--text-base);
  max-width: 36rem;
}

.site-nav,
.vault-nav,
.button-row,
.note-meta,
.ui-metadata-row,
.inline-list {
  align-items: center;
  display: flex;
  flex-wrap: wrap;
  gap: 0.7rem;
}

.site-nav a,
.vault-nav-link {
  border: 1px solid transparent;
  border-radius: var(--radius-pill);
  color: var(--ink-muted);
  font-family: var(--font-ui);
  font-size: var(--text-xs);
  font-weight: 700;
  letter-spacing: 0.12em;
  min-height: 2.8rem;
  padding: 0.72rem 1rem;
  text-transform: uppercase;
  transition:
    background-color 140ms ease,
    border-color 140ms ease,
    color 140ms ease,
    transform 140ms ease;
}

.site-nav a:hover,
.vault-nav-link:hover,
.route-tile:hover,
.note-list-link:hover,
.tag-filter-link:hover,
.primary-button:hover,
.ghost-button:hover,
.ui-button:hover {
  transform: translateY(-1px);
}

.site-nav a:hover,
.vault-nav-link:hover {
  background: rgba(255, 255, 255, 0.82);
  border-color: var(--line);
  color: var(--ink);
}

.vault-nav-link-active {
  background: var(--accent-soft);
  border-color: var(--accent-soft-strong);
  color: var(--accent-strong);
}

.feature-layout,
.note-editor-shell,
.login-layout,
.dashboard-grid,
.public-home-grid,
.link-manager-grid,
.retrieval-grid,
.route-grid,
.summary-row,
.tag-filter-list,
.detail-stack,
.note-editor-grid,
.link-form,
.link-list,
.link-list-item,
.link-list-heading,
.link-list-footer,
.tag-list,
.ui-tag-list,
.search-form,
.note-generated-panel,
.note-generated-copy,
.field-group {
  display: grid;
  gap: var(--space-4);
}

.feature-layout,
.note-editor-shell,
.public-home-grid,
.dashboard-grid,
.login-layout,
.link-manager-grid,
.retrieval-grid,
.note-editor-grid {
  grid-template-columns: minmax(0, 1fr);
}

.ui-surface,
.hero-card,
.panel-card,
.feature-card,
.vault-frame,
.public-note-metadata {
  background:
    linear-gradient(180deg, rgba(255, 255, 255, 0.56), transparent 26%),
    var(--surface);
  border: 1px solid var(--line);
  border-radius: var(--radius-4);
  box-shadow: var(--shadow-panel);
  position: relative;
}

.ui-surface::before,
.hero-card::before,
.panel-card::before,
.feature-card::before,
.vault-frame::before,
.public-note-metadata::before {
  background: linear-gradient(90deg, transparent, rgba(255, 255, 255, 0.9), transparent);
  content: "";
  height: 1px;
  left: var(--space-6);
  position: absolute;
  right: var(--space-6);
  top: 0;
}

.ui-surface,
.hero-card,
.panel-card,
.feature-card,
.vault-frame {
  padding: var(--space-5);
}

.ui-surface-hero,
.hero-card {
  box-shadow: var(--shadow-hero);
}

.ui-surface-panel,
.ui-surface-card,
.ui-surface-shell,
.panel-card,
.feature-card,
.vault-frame {
  background:
    linear-gradient(180deg, rgba(255, 255, 255, 0.58), transparent 22%),

    linear-gradient(180deg, rgba(255, 255, 255, 0.58), transparent 22%),
    var(--surface-strong);
}

.ui-surface-inset,
.public-note-metadata {
  background: var(--surface-muted);
  border-radius: var(--radius-3);
  gap: var(--space-4);
  margin-top: var(--space-6);
  padding: var(--space-4);
}

.ui-surface-inset::before,
.public-note-metadata::before {
  display: none;
}

.ui-detail-block,
.detail-block,
.publication-panel,
.note-list-item,
.link-list-item,
.route-tile,
.tag-filter-link {
  background: rgba(248, 250, 252, 0.92);
  border: 1px solid rgba(148, 163, 184, 0.22);
  border-radius: var(--radius-3);
  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.8);
}

.ui-detail-block,
.detail-block,
.publication-panel,
.note-list-item,
.link-list-item,
.route-tile {
  padding: var(--space-4);
}

.ui-detail-block strong,
.detail-block strong,
.summary-row strong,
.section-heading strong,
.ui-section-heading strong,
.note-generated-copy strong,
.panel-card strong,
.field-group span,
.sign-in-form label,
.note-meta,
.ui-metadata-row,
.brand,
.route-tile strong,
.tag-filter-link,
.primary-button,
.ghost-button,
.ui-button {
  font-family: var(--font-ui);
}

.ui-detail-block p,
.detail-block p {
  margin: 0;
}

.ui-detail-block strong,
.detail-block strong {
  display: block;
  margin-bottom: 0.4rem;
}

.hero-card h1,
.feature-card h1,
.note-preview-panel h2,
.vault-frame-title {
  font-family: var(--font-display);
  font-weight: 650;
  letter-spacing: -0.04em;
  margin: 0;
}

.hero-card h1,
.feature-card h1 {
  font-size: var(--text-display);
  line-height: 0.96;
  max-width: 15ch;
}

.note-preview-panel h2 {
  font-size: clamp(1.55rem, 3vw, 2.1rem);
  line-height: 1;
}

.vault-frame-title {
  font-size: clamp(1.3rem, 2.6vw, 1.9rem);
  line-height: 1.06;
  max-width: 28rem;
}

.lede {
  font-size: var(--text-base);
  max-width: 42rem;
}

.eyebrow {
  color: var(--accent);
  font-family: var(--font-ui);
  font-size: var(--text-xs);
  font-weight: 700;
  letter-spacing: 0.22em;
  margin: 0;
  text-transform: uppercase;
}

.summary-row {
  border-top: 1px solid var(--line);
  margin-top: var(--space-6);
  padding-top: var(--space-5);
}

.summary-row strong,
.section-heading strong,
.ui-section-heading strong,
.note-generated-copy strong,
.panel-card strong {
  display: block;
  font-size: var(--text-xs);
  font-weight: 700;
  letter-spacing: 0.16em;
  margin-bottom: 0.3rem;
  text-transform: uppercase;
}

.summary-row span,
.section-meta {
  display: block;
}

.section-heading,
.ui-section-heading {
  align-items: baseline;
  border-bottom: 1px solid var(--line);
  display: flex;
  flex-wrap: wrap;
  gap: 0.5rem 0.75rem;
  justify-content: space-between;
  margin-bottom: 0.15rem;
  padding-bottom: var(--space-4);
}

.section-meta {
  font-family: var(--font-ui);
  font-size: var(--text-xs);
  letter-spacing: 0.1em;
  text-transform: uppercase;
}

.detail-stack {
  margin-top: var(--space-4);
}

.vault-shell {
  width: 100%;
}

.vault-frame {
  display: grid;
  gap: var(--space-6);
}

.vault-frame-header {
  border-bottom: 1px solid var(--line);
  display: grid;
  gap: var(--space-4);
  padding-bottom: var(--space-5);
}

.vault-frame-body {
  display: grid;
  gap: var(--space-6);
}

.public-home-layout,
.public-note-layout,
.login-layout {
  align-items: start;
}

.public-side-panel,
.dashboard-side-panel,
.login-form-card {
  align-self: start;
}

.public-hero,
.note-editor-intro {
  overflow: hidden;
}

.note-collection-panel,
.link-list-panel,
.note-preview-panel,
.public-note-card,
.login-form-card {
  background:
    linear-gradient(180deg, rgba(255, 255, 255, 0.66), transparent 20%),
    var(--surface-strong);
}

.public-note-card {
  margin: 0 auto;
  max-width: 56rem;
}

.public-note-header {
  display: grid;
  gap: var(--space-4);
}

.public-note-lede {
  max-width: 38rem;
}

.public-note-body {
  margin-top: var(--space-5);
}

.note-editor-intro,
.note-form,
.note-preview-panel {
  min-width: 0;
}

.note-form {
  align-content: start;
}

.note-body-field {
  min-height: 0;
}

.text-input,
.note-textarea,
.sign-in-form input {
  background: rgba(248, 250, 252, 0.9);
  border: 1px solid rgba(100, 116, 139, 0.2);
  border-radius: var(--radius-2);
  color: var(--ink);
  padding: 0.92rem 1rem;
  transition:
    border-color 140ms ease,
    box-shadow 140ms ease,
    background-color 140ms ease;
  width: 100%;
}

.text-input:focus,
.note-textarea:focus,
.sign-in-form input:focus {
  background: #ffffff;
  border-color: rgba(50, 72, 99, 0.34);
  box-shadow: 0 0 0 0.2rem rgba(50, 72, 99, 0.1);
  outline: none;
}

.note-textarea {
  min-height: 25rem;
  resize: vertical;
}

.summary-textarea {
  min-height: 10rem;
}

.sign-in-form {
  display: grid;
  gap: var(--space-4);
}

.sign-in-form label {
  color: var(--ink-soft);
  display: grid;
  font-size: var(--text-sm);
  gap: 0.45rem;
  letter-spacing: 0.02em;
}

.field-group {
  gap: 0.45rem;
}

.field-group span {
  color: var(--ink-muted);
  font-size: var(--text-xs);
  letter-spacing: 0.1em;
  text-transform: uppercase;
}

.button-row {
  gap: 0.75rem;
  margin-top: 0.25rem;
}

.primary-button,
.ghost-button,
.ui-button {
  align-items: center;
  border-radius: var(--radius-pill);
  cursor: pointer;
  display: inline-flex;
  font-size: var(--text-xs);
  font-weight: 700;
  justify-content: center;
  letter-spacing: 0.12em;
  min-height: 2.8rem;
  padding: 0.72rem 1.1rem;
  text-transform: uppercase;
  transition:
    transform 140ms ease,
    background-color 140ms ease,
    border-color 140ms ease,
    color 140ms ease,
    box-shadow 140ms ease;
}

.primary-button,
.ui-button-primary {
  background: linear-gradient(180deg, #415a77 0%, var(--accent-strong) 100%);
  border: 1px solid rgba(25, 41, 59, 0.24);
  box-shadow: 0 0.85rem 1.5rem rgba(25, 41, 59, 0.18);
  color: #f8fafc;
}

.ghost-button,
.ui-button-ghost {
  background: rgba(255, 255, 255, 0.8);
  border: 1px solid var(--line);
  color: var(--ink);
}

.primary-button:focus-visible,
.ghost-button:focus-visible,
.ui-button:focus-visible,
.site-nav a:focus-visible,
.vault-nav-link:focus-visible,
.note-list-link:focus-visible,
.tag-filter-link:focus-visible {
  outline: 2px solid rgba(50, 72, 99, 0.28);
  outline-offset: 3px;
}

.status-note {
  background: var(--success-soft);
  border: 1px solid var(--success-line);
  border-radius: var(--radius-2);
  margin-top: var(--space-4);
  padding: 0.9rem 1rem;
}

.status-note-error,
.signin-error {
  background: var(--danger-soft);
  border: 1px solid var(--danger-line);
  border-radius: var(--radius-2);
  color: #991b1b;
  margin-top: var(--space-4);
  padding: 0.9rem 1rem;
}

.auth-note {
  margin-top: var(--space-4);
}

.publication-panel {
  display: grid;
  gap: var(--space-4);
  margin-top: var(--space-5);
}

.note-list,
.link-list {
  margin-top: 0.25rem;
}

.note-list-item,
.link-list-item {
  align-items: start;
}

.note-list-item-public {
  background: rgba(255, 255, 255, 0.95);
}

.note-list-link {
  color: var(--ink);
  display: inline-block;
  font-family: var(--font-display);
  font-size: clamp(1.08rem, 1.7vw, 1.38rem);
  font-weight: 650;
  letter-spacing: -0.03em;
  line-height: 1.08;
  margin-top: 0.15rem;
  transition: color 140ms ease, transform 140ms ease;
}

.note-list-link:hover {
  color: var(--accent-strong);
}

.link-url {
  font-family: var(--font-mono);
  font-size: var(--text-xs);
  overflow-wrap: anywhere;
}

.note-generated-summary {
  color: var(--ink-soft);
}

.enrichment-status-block {
  display: grid;
  gap: 0.35rem;
}

.enrichment-status-block .note-meta-leading {
  margin-bottom: 0;
}

.note-meta,
.ui-metadata-row {
  color: var(--ink-faint);
  font-size: 0.7rem;
  letter-spacing: 0.14em;
  text-transform: uppercase;
}

.note-meta-leading {
  margin-bottom: 0.2rem;
}

.link-list-footer {
  gap: var(--space-3);
}

.tag-list,
.ui-tag-list {
  align-items: start;
  grid-template-columns: repeat(auto-fit, minmax(6.5rem, max-content));
}

.tag-pill,
.ui-tag {
  align-items: center;
  background: var(--accent-soft);
  border: 1px solid var(--accent-soft-strong);
  border-radius: var(--radius-pill);
  color: var(--accent-strong);
  display: inline-flex;
  font-family: var(--font-ui);
  font-size: var(--text-xs);
  font-weight: 700;

  font-weight: 700;
  letter-spacing: 0.08em;
  min-height: 2.35rem;
  padding: 0.45rem 0.8rem;
  text-transform: uppercase;
}

.tag-pill-muted,
.ui-tag-muted {
  background: rgba(255, 255, 255, 0.7);
  border-color: var(--line);
  color: var(--ink-muted);
}

.tag-filter-list {
  grid-template-columns: repeat(auto-fit, minmax(12rem, 1fr));
}

.tag-filter-link {
  color: var(--ink);
  gap: 0.45rem;
  min-height: 4.5rem;
}

.tag-filter-link-active {
  background: rgba(239, 244, 249, 0.98);
  border-color: var(--accent-soft-strong);
}

.tag-filter-count {
  font-family: var(--font-body);
  font-size: var(--text-base);
  letter-spacing: normal;
  text-transform: none;
}

.route-grid {
  grid-template-columns: minmax(0, 1fr);
}

.route-tile {
  display: grid;
  gap: 0.4rem;
}

.route-tile strong {
  margin-bottom: 0;
}

.route-tile span {
  color: var(--ink-muted);
  line-height: 1.6;
}

.search-form {
  align-items: end;
}

.markdown-preview {
  border-top: 1px solid var(--line);
  color: var(--ink-soft);
  margin-top: var(--space-4);
  padding-top: var(--space-5);
}

.markdown-preview > :first-child {
  margin-top: 0;
}

.markdown-preview > :last-child {
  margin-bottom: 0;
}

.markdown-preview h1,
.markdown-preview h2,
.markdown-preview h3,
.markdown-preview h4,
.markdown-preview h5,
.markdown-preview h6 {
  color: var(--ink);
  font-family: var(--font-display);
  font-weight: 650;
  letter-spacing: -0.03em;
  line-height: 1.08;
  margin: 1.45rem 0 0.7rem;
}

.markdown-preview h1 {
  font-size: 1.85rem;
}

.markdown-preview h2 {
  font-size: 1.52rem;
}

.markdown-preview h3 {
  font-size: 1.22rem;
}

.markdown-preview p,
.markdown-preview li,
.markdown-preview blockquote {
  line-height: 1.74;
}

.markdown-preview p,
.markdown-preview ul,
.markdown-preview ol,
.markdown-preview pre,
.markdown-preview blockquote {
  margin: 0 0 0.95rem;
}

.markdown-preview ul,
.markdown-preview ol {
  padding-left: 1.3rem;
}

.markdown-preview code {
  background: rgba(15, 23, 42, 0.08);
  border-radius: 0.45rem;
  padding: 0.12rem 0.35rem;
}

.markdown-preview pre {
  background: #0f172a;
  border-radius: var(--radius-2);
  color: #f8fafc;
  overflow-x: auto;
  padding: 1rem;
}

.markdown-preview pre code {
  background: transparent;
  padding: 0;
}

.markdown-preview blockquote {
  border-left: 3px solid rgba(50, 72, 99, 0.32);
  color: var(--ink-muted);
  margin-left: 0;
  padding-left: 0.95rem;
}

.markdown-preview a {
  color: var(--accent-strong);
  text-decoration: underline;
  text-decoration-thickness: 1px;
  text-underline-offset: 0.18em;
}

.bullet-list {
  color: var(--ink-muted);
  display: grid;
  gap: 0.65rem;
  line-height: 1.65;
  margin: var(--space-5) 0 0;
  padding-left: 1.1rem;
}

.inline-list {
  list-style: none;
  margin: 0;
  padding: 0;
}

.inline-list li {
  border: 1px solid var(--line);
  border-radius: var(--radius-pill);
  color: var(--ink-muted);
  padding: 0.5rem 0.8rem;
}

@media (min-width: 640px) {
  .page-shell {
    padding: var(--space-5);
  }

  .ui-surface,
  .hero-card,
  .panel-card,
  .feature-card,
  .vault-frame {
    padding: var(--space-6);
  }
}

@media (min-width: 768px) {
  .page-shell {
    padding: var(--space-6);
  }

  .site-header {
    align-items: center;
    flex-direction: row;
    justify-content: space-between;
  }

  .summary-row {
    grid-template-columns: repeat(3, minmax(0, 1fr));
  }

  .public-home-grid,
  .dashboard-grid {
    grid-template-columns: minmax(0, 1.16fr) minmax(18rem, 0.84fr);
  }

  .login-layout {
    grid-template-columns: minmax(0, 1.02fr) minmax(18rem, 0.98fr);
  }

  .link-manager-grid {
    align-items: start;
    grid-template-columns: minmax(0, 0.92fr) minmax(0, 1.08fr);
  }

  .note-editor-grid {
    grid-template-columns: minmax(0, 1.02fr) minmax(0, 0.98fr);
  }

  .note-list-item {
    grid-template-columns: minmax(0, 1fr) auto;
  }

  .link-list-footer {
    align-items: center;
    grid-template-columns: minmax(0, 1fr) auto;
  }

  .retrieval-grid {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }

  .route-grid {
    grid-template-columns: repeat(3, minmax(0, 1fr));
  }
}

@media (min-width: 1024px) {
  .ui-surface,
  .hero-card,
  .panel-card,
  .feature-card,
  .vault-frame {
    padding: var(--space-7);
  }

  .vault-frame-header {
    align-items: end;
    grid-template-columns: minmax(0, 1fr) auto;
  }

  .public-note-card {
    padding: var(--space-8);
